import inspect
import warnings
from json import dumps as json_dumps
from typing import (
    Any,
    AsyncIterable,
    AsyncIterator,
    Dict,
    Iterable,
    Iterator,
    Mapping,
    Optional,
    Tuple,
    Union,
)
from urllib.parse import urlencode

from ._exceptions import StreamClosed, StreamConsumed
from ._multipart import MultipartStream
from ._types import (
    AsyncByteStream,
    RequestContent,
    RequestData,
    RequestFiles,
    ResponseContent,
    SyncByteStream,
)
from ._utils import peek_filelike_length, primitive_value_to_str


class ByteStream(AsyncByteStream, SyncByteStream):
    def __init__(self, stream: bytes) -> None:
        """Wrap a complete bytes object as a sync/async byte stream."""
        self._stream = stream

    def __iter__(self) -> Iterator[bytes]:
        """Iterate over the single bytes payload."""
        yield self._stream

    async def __aiter__(self) -> AsyncIterator[bytes]:
        """Asynchronously iterate over the single bytes payload."""
        yield self._stream


class IteratorByteStream(SyncByteStream):
    CHUNK_SIZE = 65_536

    def __init__(self, stream: Iterable[bytes]) -> None:
        """Wrap an iterable of bytes (or a file-like) as a synchronous byte stream."""
        self._stream = stream
        self._is_stream_consumed = False
        self._is_generator = inspect.isgenerator(stream)

    def __iter__(self) -> Iterator[bytes]:
        """Iterate over the underlying iterable or file-like object in chunks."""
        if self._is_stream_consumed and self._is_generator:
            raise StreamConsumed()

        self._is_stream_consumed = True
        if hasattr(self._stream, "read"):
            # File-like interfaces should use 'read' directly.
            chunk = self._stream.read(self.CHUNK_SIZE)
            while chunk:
                yield chunk
                chunk = self._stream.read(self.CHUNK_SIZE)
        else:
            # Otherwise iterate.
            for part in self._stream:
                yield part


class AsyncIteratorByteStream(AsyncByteStream):
    CHUNK_SIZE = 65_536

    def __init__(self, stream: AsyncIterable[bytes]) -> None:
        """Wrap an async iterable of bytes (or an async file-like) as an async byte stream."""
        self._stream = stream
        self._is_stream_consumed = False
        self._is_generator = inspect.isasyncgen(stream)

    async def __aiter__(self) -> AsyncIterator[bytes]:
        """Asynchronously iterate over the underlying async iterable or file-like object in chunks."""
        if self._is_stream_consumed and self._is_generator:
            raise StreamConsumed()

        self._is_stream_consumed = True
        if hasattr(self._stream, "aread"):
            # File-like interfaces should use 'aread' directly.
            chunk = await self._stream.aread(self.CHUNK_SIZE)
            while chunk:
                yield chunk
                chunk = await self._stream.aread(self.CHUNK_SIZE)
        else:
            # Otherwise iterate.
            async for part in self._stream:
                yield part


class UnattachedStream(AsyncByteStream, SyncByteStream):
    """
    If a request or response is serialized using pickle, then it is no longer
    attached to a stream for I/O purposes. Any stream operations should result
    in `httpx.StreamClosed`.
    """

    def __iter__(self) -> Iterator[bytes]:
        """Any attempt to iterate an unattached stream raises StreamClosed."""
        raise StreamClosed()

    async def __aiter__(self) -> AsyncIterator[bytes]:
        """Any attempt to asynchronously iterate an unattached stream raises StreamClosed."""
        raise StreamClosed()
        yield b""  # pragma: no cover


def encode_content(
    content: Union[str, bytes, Iterable[bytes], AsyncIterable[bytes]],
) -> Tuple[Dict[str, str], Union[SyncByteStream, AsyncByteStream]]:
    """Encode various types of request content into headers and a byte stream.

    Accepts bytes, str, iterables of bytes, and async iterables of bytes.
    Returns a tuple of headers and a stream object suitable for sending.
    """
    if isinstance(content, (bytes, str)):
        body = content.encode("utf-8") if isinstance(content, str) else content
        content_length = len(body)
        headers = {"Content-Length": str(content_length)} if body else {}
        return headers, ByteStream(body)

    # AsyncIterable check must come before Iterable, because async iterables are
    # also attributed as Iterable in some typing contexts.
    if isinstance(content, AsyncIterable):
        # We generally cannot determine the length of an async stream.
        headers = {"Transfer-Encoding": "chunked"}
        return headers, AsyncIteratorByteStream(content)

    elif isinstance(content, Iterable) and not isinstance(content, dict):
        # `not isinstance(content, dict)` is a bit oddly specific, but it
        # catches a case that's easy for users to make in error, and would
        # otherwise pass through here, like any other bytes-iterable,
        # because `dict` happens to be iterable. See issue #2491.
        content_length_or_none = peek_filelike_length(content)

        if content_length_or_none is None:
            headers = {"Transfer-Encoding": "chunked"}
        else:
            headers = {"Content-Length": str(content_length_or_none)}
        return headers, IteratorByteStream(content)

    raise TypeError("Unsupported content type: {!r}".format(type(content)))


def _prepare_urlencode_pairs(data: RequestData):
    """Normalize data into a list of (key, value) pairs with primitive string values."""
    items = []
    if isinstance(data, Mapping):
        for key, value in data.items():
            if isinstance(value, (list, tuple)):
                for v in value:
                    items.append((primitive_value_to_str(key), primitive_value_to_str(v)))
            else:
                items.append((primitive_value_to_str(key), primitive_value_to_str(value)))
    else:
        # Assume iterable of pairs
        for key, value in data:
            if isinstance(value, (list, tuple)):
                for v in value:
                    items.append((primitive_value_to_str(key), primitive_value_to_str(v)))
            else:
                items.append((primitive_value_to_str(key), primitive_value_to_str(value)))
    return items


def encode_urlencoded_data(data: Optional[RequestData]) -> Tuple[Dict[str, str], SyncByteStream]:
    """Encode data as application/x-www-form-urlencoded and return headers plus a byte stream."""
    if data is None:
        return {}, ByteStream(b"")

    # If bytes/str provided directly, just use that as the body.
    if isinstance(data, (bytes, str)):
        body = data.encode("utf-8") if isinstance(data, str) else data
        headers = {"Content-Type": "application/x-www-form-urlencoded", "Content-Length": str(len(body))}
        return headers, ByteStream(body)

    pairs = _prepare_urlencode_pairs(data)
    encoded = urlencode(pairs, doseq=True)
    body = encoded.encode("utf-8")
    headers = {"Content-Type": "application/x-www-form-urlencoded", "Content-Length": str(len(body))}
    return headers, ByteStream(body)


def encode_multipart_data(
    data: Optional[RequestData], files: Optional[RequestFiles]
) -> Tuple[Dict[str, str], Union[SyncByteStream, AsyncByteStream]]:
    """Encode data and files as multipart/form-data. Returns headers and a multipart stream."""
    data = data or {}
    files = files or {}

    multipart = MultipartStream(data, files)

    # Determine content length if available on the multipart stream.
    content_length = None
    # Try a number of common attribute/method names that may exist on MultipartStream.
    for attr in ("get_length", "getsize", "get_length", "size", "length", "content_length", "get_content_length"):
        if hasattr(multipart, attr):
            try:
                value = getattr(multipart, attr)
                content_length = value() if callable(value) else value
                break
            except Exception:
                # In case calling a method raises, ignore and continue.
                content_length = None

    boundary = getattr(multipart, "boundary", None)
    content_type = f"multipart/form-data; boundary={boundary}" if boundary else "multipart/form-data"

    if content_length is None:
        headers = {"Content-Type": content_type, "Transfer-Encoding": "chunked"}
    else:
        headers = {"Content-Type": content_type, "Content-Length": str(content_length)}

    return headers, multipart


def encode_text(content: str) -> Tuple[Dict[str, str], SyncByteStream]:
    """Encode plain text content into headers and a byte stream."""
    body = content.encode("utf-8")
    headers = {
        "Content-Type": "text/plain; charset=utf-8",
        "Content-Length": str(len(body)),
    } if body else {"Content-Type": "text/plain; charset=utf-8"}
    return headers, ByteStream(body)


def encode_html(content: str) -> Tuple[Dict[str, str], SyncByteStream]:
    """Encode HTML content into headers and a byte stream."""
    body = content.encode("utf-8")
    headers = {
        "Content-Type": "text/html; charset=utf-8",
        "Content-Length": str(len(body)),
    } if body else {"Content-Type": "text/html; charset=utf-8"}
    return headers, ByteStream(body)


def encode_json(content: Any) -> Tuple[Dict[str, str], SyncByteStream]:
    """Encode a Python object into JSON bytes and return headers and a byte stream."""
    # Allow bytes and str to pass through unmodified like other encoders.
    if isinstance(content, (bytes, str)):
        body = content.encode("utf-8") if isinstance(content, str) else content
    else:
        body = json_dumps(content, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

    headers = {
        "Content-Type": "application/json",
        "Content-Length": str(len(body)),
    } if body else {"Content-Type": "application/json"}
    return headers, ByteStream(body)